import{_ as a,o as i,c as t,a4 as n}from"./chunks/framework.BDOgl-CJ.js";const k=JSON.parse('{"title":"网络问题详解","description":"","frontmatter":{},"headers":[],"relativePath":"artifacts/network_explained.md","filePath":"artifacts/network_explained.md","lastUpdated":1777290866000}'),e={name:"artifacts/network_explained.md"};function l(p,s,h,r,d,o){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="网络问题详解" tabindex="-1">网络问题详解 <a class="header-anchor" href="#网络问题详解" aria-label="Permalink to &quot;网络问题详解&quot;">​</a></h1><h2 id="一、为什么现在能访问了" tabindex="-1">一、为什么现在能访问了？ <a class="header-anchor" href="#一、为什么现在能访问了" aria-label="Permalink to &quot;一、为什么现在能访问了？&quot;">​</a></h2><p><strong>跟 VPN 白名单无关</strong>，核心原因是 Docker 容器的<strong>网络模式</strong>从 bridge 切换成了 host。</p><h3 id="bridge-模式-之前-不通" tabindex="-1">Bridge 模式（之前，不通） <a class="header-anchor" href="#bridge-模式-之前-不通" aria-label="Permalink to &quot;Bridge 模式（之前，不通）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的 Mac ──→ 10.17.0.22:8888 ──→ docker-proxy ──→ NAT转发 ──→ 容器(10.0.0.3:8080)</span></span>
<span class="line"><span>                                     ↑</span></span>
<span class="line"><span>                                   问题在这里</span></span></code></pre></div><p>Docker 的 <code>docker-proxy</code> 进程负责在宿主机端口(8888)和容器端口(8080)之间转发。 对来自<strong>本机(localhost)</strong> 的请求，它工作正常；但对来自<strong>外部网络(10.17.x.x)</strong> 的请求，它返回了空响应。 这是 Docker bridge 网络 + iptables NAT 在特定网络拓扑下的已知行为问题。</p><h3 id="host-模式-现在-通了" tabindex="-1">Host 模式（现在，通了） <a class="header-anchor" href="#host-模式-现在-通了" aria-label="Permalink to &quot;Host 模式（现在，通了）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的 Mac ──→ 10.17.0.22:8080 ──→ Caddy 直接监听</span></span>
<span class="line"><span>                                   没有中间层</span></span></code></pre></div><p><code>--network host</code> 让容器直接使用宿主机的网络栈，Caddy 绑定在 <code>0.0.0.0:8080</code>， 和在宿主机上直接运行一个进程一样，没有任何端口转发层。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>我们加的 Clash Verge 直连规则 <code>IP-CIDR,10.0.0.0/8,DIRECT</code> 也起了作用 —— 确保你 Mac 的流量不走代理而是直接发到 10.17.0.22。两个修复缺一不可。</p></div><hr><h2 id="二、clash-verge-的直连规则在哪里设置的" tabindex="-1">二、Clash Verge 的直连规则在哪里设置的？ <a class="header-anchor" href="#二、clash-verge-的直连规则在哪里设置的" aria-label="Permalink to &quot;二、Clash Verge 的直连规则在哪里设置的？&quot;">​</a></h2><p>修改的文件路径：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/io.github.clash-verge-rev.clash-verge-rev/profiles/Merge.yaml</span></span></code></pre></div><p>这是 Clash Verge 的<strong>全局扩展配置</strong>，<code>prepend-rules</code> 中的规则会插入到所有订阅规则的<strong>最前面</strong>（优先级最高）：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">prepend-rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 公司内网服务直连</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">DOMAIN,gitlab.anyverse.work,DIRECT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">DOMAIN,docker.anyverse.work,DIRECT</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # RFC1918 私有地址段全部直连</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,10.0.0.0/8,DIRECT,no-resolve</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ← 覆盖所有 10.x.x.x 内网</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,172.16.0.0/12,DIRECT,no-resolve</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,192.168.0.0/16,DIRECT,no-resolve</span></span></code></pre></div><p>你也可以在 Clash Verge UI 中查看/编辑：<strong>订阅页面 → 全局扩展配置(Merge) → 编辑</strong>。</p><hr><h2 id="三、tun-模式-vs-系统代理的区别" tabindex="-1">三、TUN 模式 vs 系统代理的区别 <a class="header-anchor" href="#三、tun-模式-vs-系统代理的区别" aria-label="Permalink to &quot;三、TUN 模式 vs 系统代理的区别&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    subgraph &quot;系统代理 (System Proxy)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        A1[应用程序] --&gt;|&quot;读取 http_proxy 环境变量&lt;br/&gt;或系统代理设置&quot;| B1[Clash 代理端口&lt;br/&gt;127.0.0.1:7897]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        B1 --&gt; C1{规则匹配}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        C1 --&gt;|DIRECT| D1[直连目标]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        C1 --&gt;|PROXY| E1[代理服务器]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        F1[不支持代理的应用] --&gt;|&quot;绕过，不经过 Clash&quot;| D1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    end</span></span></code></pre></div><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    subgraph &quot;TUN 模式 (虚拟网卡)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        A2[所有应用程序] --&gt;|&quot;所有 TCP/UDP 流量&quot;| B2[TUN 虚拟网卡&lt;br/&gt;utun 设备]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        B2 --&gt; C2{规则匹配}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        C2 --&gt;|DIRECT| D2[直连目标]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        C2 --&gt;|PROXY| E2[代理服务器]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    end</span></span></code></pre></div><table tabindex="0"><thead><tr><th>维度</th><th>系统代理</th><th>TUN 模式</th></tr></thead><tbody><tr><td><strong>工作层级</strong></td><td>应用层 (L7)</td><td>网络层 (L3)</td></tr><tr><td><strong>覆盖范围</strong></td><td>仅支持代理设置的应用（浏览器、curl 等）</td><td><strong>所有应用</strong>的所有流量，无一例外</td></tr><tr><td><strong>实现方式</strong></td><td>设置 <code>http_proxy</code> 环境变量 + 系统代理</td><td>创建虚拟网卡 (utun)，修改路由表</td></tr><tr><td><strong>漏网之鱼</strong></td><td>不读代理变量的程序会绕过</td><td>无，全部拦截</td></tr><tr><td><strong>类比</strong></td><td>在门口贴告示&quot;请走这条路&quot;</td><td>直接把路改了，只有一条路可走</td></tr><tr><td><strong>对内网影响</strong></td><td>较小（SSH 等不走代理）</td><td>较大（必须配 DIRECT 规则否则内网也走代理）</td></tr><tr><td><strong>性能</strong></td><td>轻量</td><td>略重（多一层网卡处理）</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>你的 Clash Verge 开了 <strong>TUN 模式</strong>，所以所有流量（包括 <code>10.17.x.x</code> 内网）都被 Clash 接管。 这就是为什么必须加 <code>IP-CIDR,10.0.0.0/8,DIRECT</code> 规则 —— 告诉 Clash &quot;这些地址直连，别代理&quot;。 如果只用系统代理模式，SSH 这类不读 <code>http_proxy</code> 的工具本来就不受影响。</p></div><hr><h2 id="四、域名映射方案" tabindex="-1">四、域名映射方案 <a class="header-anchor" href="#四、域名映射方案" aria-label="Permalink to &quot;四、域名映射方案&quot;">​</a></h2><h3 id="方案-a-dns-直接访问-最简单-不需要-nginx" tabindex="-1">方案 A：DNS + 直接访问（最简单，不需要 Nginx） <a class="header-anchor" href="#方案-a-dns-直接访问-最简单-不需要-nginx" aria-label="Permalink to &quot;方案 A：DNS + 直接访问（最简单，不需要 Nginx）&quot;">​</a></h3><p>如果你有内网 DNS 管理权限（或者用公司已有的 <code>*.anyverse.work</code> 域名），只需加一条 A 记录：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>web.anyverse.work → 10.17.0.22</span></span></code></pre></div><p>然后访问 <code>http://web.anyverse.work:8080</code>。不需要 Nginx，Caddy 直接服务。</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>缺点：URL 里需要带 <code>:8080</code> 端口号。</p></div><h3 id="方案-b-dns-nginx-反向代理-推荐-标准端口" tabindex="-1">方案 B：DNS + Nginx 反向代理（推荐，标准端口） <a class="header-anchor" href="#方案-b-dns-nginx-反向代理-推荐-标准端口" aria-label="Permalink to &quot;方案 B：DNS + Nginx 反向代理（推荐，标准端口）&quot;">​</a></h3><p>如果想用 <code>http://web.anyverse.work</code>（不带端口，默认 80），需要 Nginx：</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/nginx/sites-available/web_server.conf</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">web.anyverse.work;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> / </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:8080;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Host $host;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Real-IP $remote_addr;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        proxy_set_header </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">X-Forwarded-For $proxy_add_x_forwarded_for;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="方案-c-直接让-caddy-监听-80-端口-最省事" tabindex="-1">方案 C：直接让 Caddy 监听 80 端口（最省事） <a class="header-anchor" href="#方案-c-直接让-caddy-监听-80-端口-最省事" aria-label="Permalink to &quot;方案 C：直接让 Caddy 监听 80 端口（最省事）&quot;">​</a></h3><p>容器内的 Caddy 本身就是 Web 服务器，可以直接配置它监听 80 端口，无需额外 Nginx。 需要修改容器内的 Caddyfile 或环境变量，让 Caddy 从 8080 改为监听 80。</p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>监听 80 端口需要 root 权限（或 <code>NET_BIND_SERVICE</code> capability）。 <code>--network host</code> 模式下，端口 80 如果已被占用（如已有 Nginx），会冲突。</p></div><h3 id="建议" tabindex="-1">建议 <a class="header-anchor" href="#建议" aria-label="Permalink to &quot;建议&quot;">​</a></h3><p>如果 22 机器上<strong>已有 Nginx</strong>：用方案 B，加一个 server block 反代到 8080。 如果 22 机器上<strong>没有 Nginx</strong>：用方案 C，让 Caddy 直接听 80，最简单。</p><hr><p>维护者: 基座模型组</p>`,40)])])}const g=a(e,[["render",l]]);export{k as __pageData,g as default};
